INSERT INTO `konfigurasi` (`id`, `keywords`, `deskripsi`, `nama`, `deskripsi_beranda`, `judul`, `singkatan`, `alamat`, `ukuran_biaya`, `email`, `telp`, `logo`, `bg_beranda`, `bg`, `about`, `informasi_utama`, `alur_pendaftaran`, `fb`, `ig`, `twitter`, `website`, `panduan_website`, `panduan_mahasiswa`, `kota`, `maps`, `syarat_berkas`, `wa_konfirmasi`, `wa_konfirmasi_berkas`, `batas_lulus`, `status_batas_lulus`, `status_pencairan`) VALUES
(1, '', '', 'UNIVERSITAS SIGUNTANG MAHAPUTRA', '<p>Penerimaan Mahasiswa Baru Universitas Terbaik Indonesia</p>\r\n', 'UNSIGMA', 'UNSIGMA', 'Jl. Jati No.42, Langensari, Kec. Tarogong Kaler, Kabupaten Cimahi, Jawa Barat 44151', '', 'admin@uti.ac.id', '6281380970449', 'logo-ut-pusat1.png', 'a4172a4ba1a95f22487cf977fb918e2f.jpg', 'WhatsApp_Image_2023-02-01_at_15_20_371.jpeg', '', '<p style=\"text-align:center\">Penerimaan Mahasiswa Baru Universitas Terbaik Indonesia</p>\r\n\r\n<p style=\"text-align:center\">Gelombang 1 - Februari s/d Maret 2023</p>\r\n\r\n<p style=\"text-align:center\">Gelombang 2 -&nbsp;April s/d Mei 2023</p>\r\n\r\n<p style=\"text-align:center\">Gelombang 3 -&nbsp;Juni s/d Juli 2023</p>\r\n\r\n<p style=\"text-align:center\">Gelombang 4 -&nbsp;Agustus s/d September 2023</p>\r\n', '<p>1. Mengisi formulir pada form yang sudah disesediakan<br />\r\n2. Setelah pendaftaran berhasil, maka akan muncul&nbsp;popup berupa data,&nbsp;username dan password yang akan digunakan untuk login<br />\r\n3. Silahkan login menggunakan username dan password yang tertera pada popup<br />\r\n4. Selanjutnya lengkapi semua data yang belum diisi pada menu <strong>Data Calon Mahasiswa</strong>, kami akan verifikasi jika semua data telah diisi<br />\r\n5. Jika sudah diverifikasi silahkan melakukan registrasi pendaftaran ke nomor rekening yang sudah tertera di menu&nbsp;<strong>Registrasi Pendaftaran</strong><br />\r\n6. Kirim bukti registrasi pendaftaran ke nomor WA yang tertera pada bagian bawah di menu&nbsp;<strong>Registrasi Pendaftaran</strong><br />\r\n7. Tunggu hingga registrasi pendaftaran sudah terverifikasi<br />\r\n8. Jika sudah terverifikasi nanti akan diberikan Nomor Ujian&nbsp;<br />\r\n9. Ujian akan dilaksanakan sesuai jadwal yang tersedia pada menu <strong>Jadwal Ujian</strong><br />\r\n10. Setelah ujian nanti akan ada pengumuman kelulusan, kelulusan bisa dilihat pada menu <strong>Kelulusan</strong><br />\r\n11. Setelah dinyatakan lulus silahkan untuk melakukan daftar ulang dan menghubungi bagian keuangan, nomor tersebut bisa dilihat pada menu <strong>Kontak Admin atau&nbsp;Registrasi Pendaftaran</strong></p>\r\n', '#', 'https://www.instagram.com/utiofficial/', '#', 'https://uti.ac.id', '<p><span style=\"font-size:16pt\"><span style=\"color:black\">LOGIN</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Bagian login merupakan bagian pertama yang digunakan sebelum masuk kebagian system utama, dalam bagian system utama nantinya di bagi menjadi 3 bagian, yaitu Superadmin, Admin PMB, dan Calon Mahasiswa. Untuk login Calon Mahasiswa menggunakan username dan password pada saat pendaftaran, sementara untuk Admin PMB menggunaan Username dan Passoword yang telah dibuatkan oleh Super Admin, nantinya Admin PMB akan menampilkan data pendaftar sesuai fakultasnya</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<h1 style=\"text-align:justify\"><span style=\"font-size:16pt\"><span style=\"color:black\">ADMIN</span></span></h1>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Setelah berhasil melakukan login, Super Admin berperan untuk mengatur segala kegiatan system yang telah tersedia, berikut beberapa hak akses yang bisa dilakukan oleh super admin yaitu:</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><strong><span style=\"font-size:11pt\">Menu Konfigurasi</span></strong></span></p>\r\n\r\n<p><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\">Konfigurasi Utama</span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:14.6667px\">terdapat beberapa konfigurasi yang akan ditampilkan di halaman awal website</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><em>Batas Nilai CBT </em></strong>digunaka untuk mengatur nilai kelulusan ujian CBT dari peserta jika batas nilai misalnya diisi 50.00 maka peserta yang nilai ujian cbtntya lebih dari atau sama dengan 50 akan otomatis dinyatakan lulus</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><em>Status Batas Lulus CBT&nbsp;</em></strong>untuk menampilkan atau menyembunyikan kolom <strong>ujian CBT</strong> pada menu kelulusan</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><em>Infromasi Utama </em></strong>untuk menampilkan informasi utama pada bagian beranda</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><em>Alur pendaftaran</em> </strong>bagian<strong> </strong>ini untuk mengatur alur dari pendafataran PMB pada bagian formulir pendaftaran</span></li>\r\n	<li style=\"text-align:justify\"><em><strong>Deskripsi Beranda</strong></em>&nbsp;<span style=\"font-size:11pt\">bagian ini digunakan untuk menampilkan deskripsi utama pada halaman awal website</span></li>\r\n	<li style=\"text-align:justify\"><em><strong><span style=\"font-size:11pt\">Persyaratan Deskripsi&nbsp;</span></strong></em><span style=\"font-size:11pt\">bagian ini digunakan untuk menampilkan persyaratan yang harus di upload pendaftar</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><em>Status pencairan agen&nbsp;</em></strong>untuk menampilkan atau menyembunyikan fitur pencairan pada halaman pencairan agen</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\"><strong><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\">Konfigurasi Background</span></span></strong></p>\r\n\r\n<p style=\"text-align:justify\">bagian ini digunakan untuk mengganti background dari halaman login dan beranda, untuk melihat hasilnya saat background di ganti harus di hapus terlebih dahulu bagian history browsernya.</p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Admin CBT</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Pada menu ini Super Admin atau Admin PMB akan diarahkan ke halaman login admin cbt, silahkan login menggunakan username dan password yang sama dengan login ke website PMB</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><strong><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\">Menu kalkulasi</span></span></strong></p>\r\n\r\n<p><strong><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\">Kalkulasi Pendaftar</span></span></strong></p>\r\n\r\n<p><span style=\"font-size:11pt\">bagian ini digunakan untuk menampilkan kalulasi pendaftar yang baru daftar / belum bayar, sudah bayar, terverifikasi, diterima dan juga yang sudah registrasi ulang</span></p>\r\n\r\n<p><strong><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\">Kalkulasi Agen</span></span></strong></p>\r\n\r\n<p><span style=\"font-size:11pt\">bagian ini digunakan untuk menampilkan&nbsp;data pendaftar yang dilakukan oleh agen berupa data pendaftar awal / belum bayar, sudah bayar, terverifikasi dan juga pengajuan agen tersebut</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><strong><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\">Menu Agen</span></span></strong></p>\r\n\r\n<p><strong><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\">Data Agen</span></span></strong></p>\r\n\r\n<p><span style=\"font-size:11pt\">bagian ini digunakan untuk menampilkan data agen yang sudah mendaftar</span></p>\r\n\r\n<p><strong><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\">Jenis Agen</span></span></strong></p>\r\n\r\n<p><span style=\"font-size:11pt\">bagian ini digunakan untuk membuat jenis agen dan juga komisi yang akan di dapat agen</span></p>\r\n\r\n<p><strong><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\">Link Agen</span></span></strong></p>\r\n\r\n<p><span style=\"font-size:11pt\">bagian ini digunakan masuk ke halaman login agen</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><strong><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\">Menu Tahun Akademik</span></span></strong></p>\r\n\r\n<p><span style=\"color:#2ecc71\"><span style=\"font-size:14.6667px\"><strong>Tahun Akdemik</strong></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\">bagian ini digunakan untuk menambahkan tahun akademik dan bagian vital dari PMB, karena pendaftaran PMB akan bisa dilakukan jika status tahun akademik <strong>aktif </strong>dan <strong>masih berlaku</strong></span></li>\r\n	<li><span style=\"font-size:14.6667px\">data tahun akademik yang sudah dibuat akan otomatis dibuatkan grup untuk tes, jadi saat nanti membuat tes di website cbt pastikan grup yang dipilih untuk tese sesuai pada saat tahun akademik yang sedang berjalan atau masih berlaku</span></li>\r\n	<li><span style=\"font-size:11pt\">tahun akademik yang akan masuk saat pendaftaran adalah tahun akademik yang terbaru status <strong>aktif </strong>dan <strong>masih berlaku</strong></span></li>\r\n</ul>\r\n\r\n<p><span style=\"color:#2ecc71\"><span style=\"font-size:14.6667px\"><strong>Tahun Akdemik Admin</strong></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\">bagian ini digunakan untuk menampilkan data pendaftar sesuai tahun akademik admin yang <strong>aktif</strong></span></li>\r\n	<li><span style=\"font-size:11pt\">data yang akan telihat pada menu belum bayar, sudah bayar, terverifikasi dan diterima yaitu yang status tahun akademiknya <strong>aktif</strong></span></li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Master</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\"><strong>Menu Gelombang</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">bagian ini digunakan untuk menampilkan gelombang pendaftaran di bagian formulir pendaftaran </span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">gelombang yang nanti akan tampil sesuai dengan fakultas yang di pilih</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">gelombang yang akan tampil yang statusnya aktif</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">gelombang akan berakhir sesuai tanggal yang di tentukan</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\"><strong>Program Pendaftaran</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">program yang akan di tampilkan adalah program yang statusnya aktif</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">untuk kode diharuskan berbeda-beda</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\"><strong>Program Studi</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">bagian ini digunakan untuk membuat prodi sesuai fakultas</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">prodi yang akan di tampilkan untuk calon pendaftar adalah yang statusnya aktif</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">untuk bagian biaya, nomor rekening dan nama bank harus diisi agar saat calon mahasiswa daftar, mendapat informasi mengenai registrasi pembayaran</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">diusahakan untuk kode prodi harus berbeda-beda</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\"><strong>List Biaya</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">bagian ini digunakan untuk membuat daftar biaya berupa detailnya</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">list biaya ini akan tampil pada halaman awal website</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">yang akan ditampilkan pada halaman awal website jika statusnya aktif dan utamanya yes</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Belum Bayar</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Pada menu ini Super Admin atau Admin PMB akan melihat data pendaftar yang baru masuk dan baru bayar.</span><span style=\"font-size:11pt\">&nbsp;berikut beberapa fitur pada menu verifikasi :</span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Filter data berdasarkan Fakultas dan gelombang, setelah itu baru bisa backup data mahasiswa yang belum bayar</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa chat WA kepada pendaftar dengan syarat nomor WA yang di daftarkan peserta benar - bernar terdaftar di WA dan format nomor WA nya harus menggunakan awalan 62, seperti contoh ini 62897979799xxx</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa melihat detail bukti registrasi pembayaran yang dilakukan mahasiswa</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Memverifikasi data pembayaran dengan klik tombol verifikasi pembayaran</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Sudah Bayar</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Pada menu ini Super Admin atau Admin PMB akan melihat data pendaftar yang pembayaranya sudah diverifikasi.</span><span style=\"font-size:11pt\">&nbsp;berikut beberapa fitur pada menu verifikasi :</span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Filter data berdasarkan Fakultas dan gelombang, setelah itu baru bisa backup data mahasiswa yang baru diverifikasi pembayaranya</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa chat WA kepada pendaftar dengan syarat nomor WA yang di daftarkan peserta benar - bernar terdaftar di WA dan format nomor WA nya harus menggunakan awalan 62, seperti contoh ini 62897979799xxx</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa melihat berkas yang di upload peserta, memverifikasi dan menolak berkas peserta dan nantinya akan ada informasi belum diverifikasi, berkas ditolak dan terverifikasi pada bagian dasbor mahasiswa ataupun pada bagian menu verifikasi sendiri</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa melihat detail bukti registrasi pembayaran yang dilakukan mahasiswa</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Memverifikasi data mahasiswa sehingga nantinya data yang sudah di verifikasi pada menu sudah bayar akan pindah ke menu terverifikasi</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa melihat detail dan edit data mahasiswa juga edit prodi olehh admin</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Terverifikasi</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Pada menu ini Super Admin atau Admin PMB akan melihat data pendaftar yang pembayaran dan datanya&nbsp;sudah diverifikasi.</span><span style=\"font-size:11pt\">&nbsp;berikut beberapa fitur pada menu verifikasi :</span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">setelah pendaftar terverifikasi maka akun cbt pendaftar akan dibuatkan otomatis dan pendaftar bisa klik link dan bisa login dengan username dan password yang telah didaftarkan pada website pmb</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:14.6667px\">pendaftar yang akan mengikuti tes adalah pendaftar yang sudah masuk menu ini</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Filter data berdasarkan gelombang dan jurusan setelah itu baru </span><span style=\"font-size:11pt\">bisa backup data mahasiswa yang sudah di verifikasi dan akan mengikuti tes</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">bisa generate nomor urut ujian, pada saat generate atau ganti no ujian pastikan filter dlu datanya berdasarkan fakultas dan gelombang</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa melihat berkas yang di upload peserta</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa generate dan ganti nomor ujian peserta, agar semuanya berurutan maka sebelum generate atau ganti nomor ujian filter dulu datanya</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa mencetak kartu ujian peserta</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa mencetak formulir pendaftaran peserta</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa menolak status verifikasi, jadi data akan di kembalikan ke menu sudah bayar</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa meluluskan atau mengagalkan kelulusan mahasiswa</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">bisa meluluskan peserta ke pilihan 2 jika pilihan 1 dan 2 nya berbeda</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">bisa dan edit data pesera</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Diterima</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Filter data berdasarkan fakultas dan gelombang, setelah itu&nbsp;</span><span style=\"font-size:11pt\">bisa backup data mahasiswa yang sudah lulus atau diterima</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa melihat berkas yang di upload peserta </span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Bisa menggagalkan status kelulusan, jadi data akan di kembalikan ke menu terverifikasi</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">bisa&nbsp;edit data pesera</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Kelulusan</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Pada menu ini admin dan peserta bisa melihat data kelulusan peserta berdasarkan fakultas dan gelombang, jika pada konfigurasi utama status batas lulus aktif maka saat filter kelulusan akan tampil kolom status CBT, yaitu berupa peserta yang sudah ikut tes menggunakan link cbt yang sudah disediakan dan akan otomatis ada keterangan lulus tidaknya jika pada konfigurasi utama batas nilai lulusnya diisi, misal 50.00</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Ujian Saringan Masuk</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Jenis USM membuat jenis ujian saringan masuk </span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Jadwal USM membuat jadwal ujian sesuai gelombang dan nanti akan tampil jadwal yang sudah di tentukan di kartu ujian</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">tempat untuk menambahkan lokasi ujian</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Informasi</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\"><strong>Menu Berita</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini berisi berita berupa pengumuman atau informasi dan nantinya akan di tampilkan di halaman utama juka statusnya publish, dan hanya admin yang dapat membuka menu ini</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\"><strong>Menu Galeri</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini berisi foto galeri yang nantinya akan di tampilkan di halaman utama jika statusnya publish, dan hanya admin yang dapat membuka menu ini</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Users</strong></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\"><strong>Menu Pengguna</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:14.6667px\">berupa akun pendaftar, dan ada tombol untuk menonaktifkan pendaftar jika admin ingin menonaktifkan akun supaya tidak bisa login</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#2ecc71\"><span style=\"font-size:11pt\"><strong>Menu Admin</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:14.6667px\">berupa akun admin dan admin fakultas, dan ada tombol edit juga ada tombol&nbsp;untuk menonaktifkan admin fakultas jika admin ingin menonaktifkan akun supaya tidak bisa login</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"color:#e74c3c\"><span style=\"font-size:11pt\"><strong>Menu Backup</strong></span></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Export data excel semua peserta</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Export data Excel semua peserta tahunan</span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Backup Database PMB</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', '<p><span style=\"font-size:16pt\"><span style=\"color:black\">LOGIN</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Calon Mahasiswa menggunakan username dan password pada saat pendaftaran.</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p><span style=\"font-size:16pt\"><span style=\"color:black\">CALON MAHASISWA</span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Setelah berhasil melakukan login, peserta dapat mengakses beberapa menu berikut:</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#e74c3c\">Menu Registrasi Pendaftaran</span></strong></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:black\">Pada menu </span>Registrasi Pendaftaran<span style=\"color:black\">&nbsp;mahasiswa dapat mengupload bukti pembayaran dengan maksimal ukuran gambar 500&nbsp;kb</span></span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"color:black\">jika sudah melakukan upload bukti pembayaran silahkan melakukan konfirmasi ke no wa yang sudah tersedia di bawah tombol upload</span></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#e74c3c\">Menu Data Calon Mahasiswa</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#2ecc71\">Menu Form Utama</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini berisi form pengisian data-data utama</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#2ecc71\">Menu Lanjutan</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini berisi form pengisian data-data lanjutan mengenai data pribadi dan sekolah / perguruan tinggi</span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#2ecc71\">Menu Orang tua / wali</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini berisi form pengisian data-data orang tuan atau wali</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#e74c3c\">Cetak Formulir</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini digunakan untuk mencetak formulir berupa data-data yang telah diisi peserta </span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#e74c3c\">Cetak Kartu Ujian</span></strong></span></p>\r\n\r\n<ul>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini digunakan untuk mencetak kartu ujian peserta, peserta bisa mencetak kartu ujian jika sudah ada nomor ujian </span></li>\r\n	<li style=\"text-align:justify\"><span style=\"font-size:11pt\">Pada menu ini juga peserta diharuskan mengupload foto profil dengan ukuran gambar maksimal 50&nbsp;KB</span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#e74c3c\">Kontak Admin</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini berisi nomor - nomor WA admin yang bisa dihubungi peserta</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#e74c3c\">Upload Berkas</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Menu ini digunakan peserta untuk mengupload persyaratan&nbsp;berkas-berkas&nbsp;dalam 1 file berupa word atau pdf maksimal file 3 MB.</span></p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><strong><span style=\"color:#e74c3c\">Link CBT</span></strong></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:11pt\">Akan muncul link CBT jika status mahasiswa sudah terverifikasi oleh admin, dan peserta bisa login sesuai username dan password yang digunakan untuk login ke website PMB</span></p>\r\n', 'Palembang', '<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3957.232772758659!2d108.2122371509271!3d-7.327732474074806!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e6f5747f9d5fd3b%3A0xa5cdb7ee8b21c05b!2sUtama%20Sport!5e0!3m2!1sen!2sid!4v1675762642400!5m2!1sen!2sid\" width=\"100%\" height=\"350\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>', '<p style=\"text-align:center\"><strong>Tabel Persyaratan dan Jenis Seleksi Jalur Bebas Tes</strong></p>\r\n\r\n<table border=\"1\" cellspacing=\"0\">\r\n	<thead>\r\n		<tr>\r\n			<th scope=\"col\">Jalur Seleksi</th>\r\n			<th scope=\"col\">Uraian</th>\r\n			<th scope=\"col\">Syarat dan Berkas</th>\r\n		</tr>\r\n	</thead>\r\n	<tbody>\r\n		<tr>\r\n			<td>PMDK-RAPORT</td>\r\n			<td>adalah penelusuran minat dan kemampuan berdasar nilai raport.</td>\r\n			<td>Rata- rata nilai raport 80 pada semester 1-5 untuk pelajaran matematika, kimia, fisika, biologi dan bahasa inggris<br />\r\n			(Berkas: Upload berkas berupa file pdf, didalamnya terdapat hasil scan rata-rata nilai raport)</td>\r\n		</tr>\r\n		<tr>\r\n			<td>PMDK-SSO</td>\r\n			<td>adalah penelusuran minat dan kemampuan berdasar seni, sains, olahraga.</td>\r\n			<td>Minimal juara tingkat provinsi<br />\r\n			(Berkas: Upload berkas berupa file pdf, didalamnya terdapat hasil scan sertifikat)</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p style=\"text-align:center\"><strong>Tabel Persyaratan Berkas Non-PMDK yang Harus di Upload</strong></p>\r\n\r\n<table border=\"1\" cellspacing=\"0\">\r\n	<thead>\r\n		<tr>\r\n			<th scope=\"col\">Jalur Seleksi</th>\r\n			<th scope=\"col\">Syarat dan Berkas</th>\r\n		</tr>\r\n	</thead>\r\n	<tbody>\r\n		<tr>\r\n			<td>Non-PMDK</td>\r\n			<td>berikut berkas - berkas yang harus disiapkan berupa SCAN Ijazah, SKHU, KTP/KK, Transkip Nilai, Suket Kerja (jika bekerja)</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<hr />\r\n<p>Jika file lebih dari 3 mb tidak bisa di upload dan silahkan anda compress&nbsp;<a href=\"https://www.ilovepdf.com/id/mengompres-pdf\" target=\"_blank\">disini</a>&nbsp;untuk (PDF) dan&nbsp;<a href=\"https://smallpdf.com/blog/compress-word\" target=\"_blank\">disini</a>&nbsp;untuk Word<br />\r\n<br />\r\n<strong>Langkah-langkah membuat PDF :</strong><br />\r\n1. Buka Microsoft Word<br />\r\n2. Copy Foto / Scan berkas<br />\r\n3. Paste di Word<br />\r\n4. Save File / Export (Klik Create PDF)</p>\r\n', '6281234857895', '6281234857894', '30.00', 0, 0);

